#include "pytorch_npu_helper.hpp"

at::Tensor conv2d_standard_impl_npu(const at::Tensor& self, const at::Tensor& weight) {
    TORCH_CHECK(self.dim() == 4, "Input must be NCHW");
    TORCH_CHECK(weight.dim() == 4, "Weight must be OIHW");

    auto N = self.size(0);
    auto C = self.size(1);
    auto H = self.size(2);
    auto W = self.size(3);

    auto Cout = weight.size(0);
    auto Cw   = weight.size(1);
    auto Kh   = weight.size(2);
    auto Kw   = weight.size(3);

    TORCH_CHECK(C == Cw, "Input C must equal weight C");

    TORCH_CHECK(H >= Kh && W >= Kw, "Invalid kernel larger than input");
    auto Ho = H - Kh + 1;
    auto Wo = W - Kw + 1;

    at::Tensor result = at::empty({N, Cout, Ho, Wo}, self.options());
    EXEC_NPU_CMD(aclnnConvStandard2dAsymmetricInputAsymmetricKernelCustom, self, weight, result);
    return result;
}

